import { useState, useEffect, useCallback } from 'react';
import leaveService from '../services/leaveService';

export const useLeaveBalance = () => {
  const [balance, setBalance] = useState(null);
  const [loading, setLoading] = useState(true);

  const fetch = useCallback(async () => {
    try {
      const { data } = await leaveService.getMyBalance();
      setBalance(data.data.balance);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetch(); }, [fetch]);
  return { balance, loading, refresh: fetch };
};

export const useLeaves = (params) => {
  const [leaves, setLeaves] = useState([]);
  const [pagination, setPagination] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetch = useCallback(async () => {
    try {
      setLoading(true);
      const { data } = await leaveService.getMyLeaves(params);
      setLeaves(data.data);
      setPagination(data.pagination || {});
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [JSON.stringify(params)]); // eslint-disable-line

  useEffect(() => { fetch(); }, [fetch]);
  return { leaves, pagination, loading, error, refresh: fetch };
};

export const useAllLeaves = (params) => {
  const [leaves, setLeaves] = useState([]);
  const [pagination, setPagination] = useState({});
  const [loading, setLoading] = useState(true);

  const fetch = useCallback(async () => {
    try {
      setLoading(true);
      const { data } = await leaveService.getAll(params);
      setLeaves(data.data);
      setPagination(data.pagination || {});
    } finally {
      setLoading(false);
    }
  }, [JSON.stringify(params)]); // eslint-disable-line

  useEffect(() => { fetch(); }, [fetch]);
  return { leaves, pagination, loading, refresh: fetch };
};
